module RefModule (
    input wire S,
    input wire R,
    input wire clk,
    output reg Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (S && !R)
            Q <= 1; // Set
        else if (!S && R)
            Q <= 0; // Reset
        // If both S and R are low, maintain current state (hold)
    end
endmodule
